local Signal = {}
Signal.__index = Signal

function Signal.new()
    return setmetatable({ _handlers = {} }, Signal)
end

function Signal:Connect(fn)
    self._handlers[fn] = true
    return { Disconnect = function() self._handlers[fn] = nil end }
end

function Signal:Fire(...)
    for fn in pairs(self._handlers) do
        task.spawn(fn, ...)       -- isolate handlers; one error won't stop the rest
    end
end

return Signal
